    /// RLP Encoding for Ethereum transactions
    static func rlpEncode(_ items: [Any]) -> Data {
        var encoded = Data()
        for item in items {
            if let data = item as? Data {
                encoded.append(rlpEncodeBytes(data))
            } else if let string = item as? String {
                encoded.append(rlpEncodeBytes(Data(string.utf8)))
            } else if let number = item as? Int {
                if number == 0 {
                    encoded.append(rlpEncodeBytes(Data()))
                } else {
                    encoded.append(rlpEncodeBytes(encodeBigEndian(number)))
                }
            } else if let array = item as? [Any] {
                let innerEncoded = rlpEncode(array)
                encoded.append(rlpEncodeLength(innerEncoded.count, offset: 0xc0))
                encoded.append(innerEncoded)
            }
        }
        return encoded
    }
    
    static func rlpEncodeBytes(_ data: Data) -> Data {
        if data.count == 1 && data[0] < 0x80 {
            return data
        }
        var result = rlpEncodeLength(data.count, offset: 0x80)
        result.append(data)
        return result
    }
    
    static func rlpEncodeLength(_ length: Int, offset: UInt8) -> Data {
        if length < 56 {
            return Data([offset + UInt8(length)])
        }
        let lengthBytes = encodeBigEndian(length)
        var result = Data([offset + 55 + UInt8(lengthBytes.count)])
        result.append(lengthBytes)
        return result
    }
    
    static func encodeBigEndian(_ value: Int) -> Data {
        guard value > 0 else { return Data() }
        var bytes: [UInt8] = []
        var v = value
        while v > 0 {
            bytes.insert(UInt8(v & 0xff), at: 0)
            v >>= 8
        }
        return Data(bytes)
    }
