// MARK: - Key Generation Service

final class KeyGenerationService {
    static let shared = KeyGenerationService()
    
    private init() {}
    
    struct GeneratedWallet {
        let wallet: Wallet
        let mnemonic: [String]
        let privateKeyHex: String
    }
    
    /// Generate a new wallet with key pair
    func generateWallet() throws -> GeneratedWallet {
        // Generate P256 key pair (secp256r1)
        // NOTE: For production Ethereum wallet, use secp256k1 via a C library
        let privateKey = P256.Signing.PrivateKey()
        let publicKey = privateKey.publicKey
        
        let privateKeyData = privateKey.rawRepresentation
        let publicKeyHex = CryptoUtils.hexString(from: publicKey.x963Representation)
        let address = CryptoUtils.deriveAddress(from: publicKey)
        
        // Store private key in Keychain
        try KeychainManager.shared.savePrivateKey(privateKeyData, forAddress: address)
        
        // Generate mnemonic for backup
        let mnemonic = CryptoUtils.generateMnemonic()
        
        let wallet = Wallet(
            address: address,
            publicKeyHex: publicKeyHex,
            createdAt: Date()
        )
        
        // Save wallet metadata
        WalletStorageService.shared.saveWallet(wallet)
        
        return GeneratedWallet(
            wallet: wallet,
            mnemonic: mnemonic,
            privateKeyHex: CryptoUtils.hexString(from: privateKeyData)
        )
    }
    
    /// Import wallet from private key hex
    func importWallet(privateKeyHex: String) throws -> Wallet {
        guard let keyData = CryptoUtils.data(fromHex: privateKeyHex) else {
            throw WalletError.invalidPrivateKey
        }
        
        let privateKey = try P256.Signing.PrivateKey(rawRepresentation: keyData)
        let publicKey = privateKey.publicKey
        
        let publicKeyHex = CryptoUtils.hexString(from: publicKey.x963Representation)
        let address = CryptoUtils.deriveAddress(from: publicKey)
        
        try KeychainManager.shared.savePrivateKey(keyData, forAddress: address)
        
        let wallet = Wallet(
            address: address,
            publicKeyHex: publicKeyHex,
            createdAt: Date()
        )
        
        WalletStorageService.shared.saveWallet(wallet)
        
        return wallet
    }
    
    /// Delete a wallet
    func deleteWallet(address: String) throws {
        try KeychainManager.shared.deletePrivateKey(forAddress: address)
        WalletStorageService.shared.removeWallet(address: address)
    }
}

// MARK: - Wallet Storage Service (metadata, not keys)

final class WalletStorageService {
    static let shared = WalletStorageService()
    
    private let walletsKey = "com.cryptowallet.wallets"
    private let defaults = UserDefaults.standard
    
    private init() {}
    
    func saveWallet(_ wallet: Wallet) {
        var wallets = loadWallets()
        wallets.removeAll { $0.address == wallet.address }
        wallets.append(wallet)
        
        if let data = try? JSONEncoder().encode(wallets) {
            defaults.set(data, forKey: walletsKey)
        }
    }
    
    func loadWallets() -> [Wallet] {
        guard let data = defaults.data(forKey: walletsKey),
              let wallets = try? JSONDecoder().decode([Wallet].self, from: data) else {
            return []
        }
        return wallets
    }
    
    func removeWallet(address: String) {
        var wallets = loadWallets()
        wallets.removeAll { $0.address == address }
        
        if let data = try? JSONEncoder().encode(wallets) {
            defaults.set(data, forKey: walletsKey)
        }
    }
    
    func getWallet(address: String) -> Wallet? {
        return loadWallets().first { $0.address == address }
    }
}

// MARK: - Transaction Signing Service

final class TransactionSigningService {
    static let shared = TransactionSigningService()
    
    private init() {}
    
    /// Sign a transaction with the wallet's private key
    func signTransaction(_ transaction: Transaction) throws -> SignedTransaction {
        // Load private key from Keychain
        let privateKeyData = try KeychainManager.shared.loadPrivateKey(forAddress: transaction.from)
        let privateKey = try P256.Signing.PrivateKey(rawRepresentation: privateKeyData)
        
        // Encode transaction for signing (RLP encoding)
        let encodedTx = encodeTransaction(transaction)
        
        // Hash the encoded transaction
        let txHash = CryptoUtils.keccak256(encodedTx)
        
        // Sign the hash
        let signature = try privateKey.signature(for: txHash)
        let signatureData = signature.rawRepresentation
        
        // Split signature into r, s components
        let rData = signatureData.prefix(32)
        let sData = signatureData.suffix(32)
        
        let r = CryptoUtils.hexString(from: Data(rData))
        let s = CryptoUtils.hexString(from: Data(sData))
        
        // Calculate v value (EIP-155)
        let v = transaction.chainId * 2 + 35
        
        // Create raw transaction with signature
        let rawTx = encodeSignedTransaction(transaction, v: v, r: Data(rData), s: Data(sData))
        let rawTxHex = "0x" + CryptoUtils.hexString(from: rawTx)
        
        return SignedTransaction(
            transaction: transaction,
            signature: CryptoUtils.hexString(from: signatureData),
            v: v,
            r: "0x" + r,
            s: "0x" + s,
            rawTransaction: rawTxHex
        )
    }
    
    /// Sign arbitrary message data
    func signMessage(_ message: Data, withAddress address: String) throws -> Data {
        let privateKeyData = try KeychainManager.shared.loadPrivateKey(forAddress: address)
        let privateKey = try P256.Signing.PrivateKey(rawRepresentation: privateKeyData)
        
        // Ethereum signed message prefix
        let prefix = "\u{19}Ethereum Signed Message:\n\(message.count)"
        var prefixedMessage = Data(prefix.utf8)
        prefixedMessage.append(message)
        
        let messageHash = CryptoUtils.keccak256(prefixedMessage)
        let signature = try privateKey.signature(for: messageHash)
        
        return signature.rawRepresentation
    }
    
    /// Sign personal message (string)
    func signPersonalMessage(_ message: String, withAddress address: String) throws -> String {
        let messageData = Data(message.utf8)
        let signatureData = try signMessage(messageData, withAddress: address)
        return "0x" + CryptoUtils.hexString(from: signatureData)
    }
    
    // MARK: - Private Encoding Methods
    
    private func encodeTransaction(_ tx: Transaction) -> Data {
        let nonce = tx.nonce
        let gasPrice = hexToInt(tx.gasPrice)
        let gasLimit = hexToInt(tx.gasLimit)
        let toData = CryptoUtils.data(fromHex: tx.to) ?? Data()
        let value = hexToInt(tx.value)
        let data = CryptoUtils.data(fromHex: tx.data) ?? Data()
        
        // EIP-155 encoding: [nonce, gasPrice, gasLimit, to, value, data, chainId, 0, 0]
        let items: [Any] = [nonce, gasPrice, gasLimit, toData, value, data, tx.chainId, 0, 0]
        return CryptoUtils.rlpEncode(items)
    }
    
    private func encodeSignedTransaction(_ tx: Transaction, v: Int, r: Data, s: Data) -> Data {
        let nonce = tx.nonce
        let gasPrice = hexToInt(tx.gasPrice)
        let gasLimit = hexToInt(tx.gasLimit)
        let toData = CryptoUtils.data(fromHex: tx.to) ?? Data()
        let value = hexToInt(tx.value)
        let data = CryptoUtils.data(fromHex: tx.data) ?? Data()
        
        let items: [Any] = [nonce, gasPrice, gasLimit, toData, value, data, v, r, s]
        return CryptoUtils.rlpEncode(items)
    }
    
    private func hexToInt(_ hex: String) -> Int {
        var hexString = hex
        if hexString.hasPrefix("0x") {
            hexString = String(hexString.dropFirst(2))
        }
        return Int(hexString, radix: 16) ?? 0
    }
}

// MARK: - Blockchain Communication Service

final class BlockchainService {
    static let shared = BlockchainService()
    
    // Default to Ethereum mainnet; can be changed for testnets
    var rpcURL: URL
    var chainId: Int
    
    private let session: URLSession
    private var requestId: Int = 0
    
    enum Network {
        case ethereumMainnet
        case ethereumGoerli
        case ethereumSepolia
        case custom(url: String, chainId: Int)
        
        var rpcURL: URL {
            switch self {
            case .ethereumMainnet:
                return URL(string: "https://eth.llamarpc.com")!
            case .ethereumGoerli:
                return URL(string: "https://goerli.infura.io/v3/YOUR_INFURA_KEY")!
            case .ethereumSepolia:
                return URL(string: "https://sepolia.infura.io/v3/YOUR_INFURA_KEY")!
            case .custom(let url, _):
                return URL(string: url)!
            }
        }
        
        var chainId: Int {
            switch self {
            case .ethereumMainnet: return 1
            case .ethereumGoerli: return 5
            case .ethereumSepolia: return 11155111
            case .custom(_, let chainId): return chainId
            }
        }
    }
    
    init(network: Network = .ethereumMainnet) {
        self.rpcURL = network.rpcURL
        self.chainId = network.chainId
        
        let config = URLSessionConfiguration.default
        config.timeoutIntervalForRequest = 30
        config.timeoutIntervalForResource = 60
        self.session = URLSession(configuration: config)
    }
    
    func switchNetwork(_ network: Network) {
        self.rpcURL = network.rpcURL
        self.chainId = network.chainId
    }
    
    // MARK: - RPC Methods
    
    private func nextRequestId() -> Int {
        requestId += 1
        return requestId
    }
    
    private func makeRPCRequest(method: String, params: [JSONRPCParam]) async throws -> String {
        let request = JSONRPCRequest(
            jsonrpc: "2.0",
            method: method,
            params: params,
            id: nextRequestId()
        )
        
        var urlRequest = URLRequest(url: rpcURL)
        urlRequest.httpMethod = "POST"
        urlRequest.setValue("application/json", forHTTPHeaderField: "Content-Type")
        urlRequest.httpBody = try JSONEncoder().encode(request)
        
        let (data, response) = try await session.data(for: urlRequest)
        
        guard let httpResponse = response as? HTTPURLResponse,
              (200...299).contains(httpResponse.statusCode) else {
            throw WalletError.networkError("HTTP request failed")
        }
        
        let rpcResponse = try JSONDecoder().decode(JSONRPCResponse.self, from: data)
        
        if let error = rpcResponse.error {
            throw WalletError.rpcError(error.message)
        }
        
        guard let result = rpcResponse.result else {
            throw WalletError.rpcError("Empty result")
        }
        
        return result
    }
    
    /// Get balance for an address
    func getBalance(address: String) async throws -> BlockchainBalance {
        let result = try await makeRPCRequest(
            method: "eth_getBalance",
            params: [.string(address), .string("latest")]
        )
        
        let weiString = result
        let wei = hexToDecimal(weiString)
        let eth = Double(wei) / 1e18
        
        return BlockchainBalance(
            address: address,
            balance: weiString,
            balanceEth: eth
        )
    }
    
    /// Get transaction count (nonce) for an address
    func getTransactionCount(address: String) async throws -> Int {
        let result = try await makeRPCRequest(
            method: "eth_getTransactionCount",
            params: [.string(address), .string("latest")]
        )
        
        return hexToInt(result)
    }
    
    /// Get current gas price
    func getGasPrice() async throws -> String {
        let result = try await makeRPCRequest(
            method: "eth_gasPrice",
            params: []
        )
        return result
    }
    
    /// Estimate gas for a transaction
    func estimateGas(from: String, to: String, value: String, data: String = "0x") async throws -> String {
        let txParams: [String: String] = [
            "from": from,
            "to": to,
            "value": value,
            "data": data
        ]
        
        let result = try await makeRPCRequest(
            method: "eth_estimateGas",
            params: [.dict(txParams)]
        )
        return result
    }
    
    /// Send a signed raw transaction
    func sendRawTransaction(_ rawTransaction: String) async throws -> String {
        let result = try await makeRPCRequest(
            method: "eth_sendRawTransaction",
            params: [.string(rawTransaction)]
        )
        return result // Returns transaction hash
    }
    
    /// Get transaction receipt
    func getTransactionReceipt(txHash: String) async throws -> TransactionReceipt {
        let result = try await makeRPCRequest(
            method: "eth_getTransactionReceipt",
            params: [.string(txHash)]
        )
        
        // Parse the receipt from the result
        return TransactionReceipt(
            transactionHash: txHash,
            blockNumber: result,
            status: nil,
            gasUsed: nil
        )
    }
    
    /// Get current block number
    func getBlockNumber() async throws -> Int {
        let result = try await makeRPCRequest(
            method: "eth_blockNumber",
            params: []
        )
        return hexToInt(result)
    }
    
    /// Build and send a transaction
    func buildAndSendTransaction(
        from: String,
        to: String,
        valueInWei: String,
        data: String = "0x"
    ) async throws -> String {
        // Get nonce
        let nonce = try await getTransactionCount(address: from)
        
        // Get gas price
        let gasPrice = try await getGasPrice()
        
        // Estimate gas
        let gasLimit = try await estimateGas(from: from, to: to, value: valueInWei, data: data)
        
        // Build transaction
        let transaction = Transaction(
            from: from,
            to: to,
            value: valueInWei,
            nonce: nonce,
            gasPrice: gasPrice,
            gasLimit: gasLimit,
            chainId: chainId,
            data: data
        )
        
        // Sign transaction
        let signedTx = try TransactionSigningService.shared.signTransaction(transaction)
        
        // Send transaction
        let txHash = try await sendRawTransaction(signedTx.rawTransaction)
        
        // Store transaction in history
        TransactionHistoryService.shared.addTransaction(
            hash: txHash,
            from: from,
            to: to,
            value: valueInWei,
            status: .pending
        )
        
        return txHash
    }
    
    // MARK: - Utility
    
    private func hexToInt(_ hex: String) -> Int {
        var hexString = hex
        if hexString.hasPrefix("0x") {
            hexString = String(hexString.dropFirst(2))
        }
        return Int(hexString, radix: 16) ?? 0
    }
    
    private func hexToDecimal(_ hex: String) -> UInt64 {
        var hexString = hex
        if hexString.hasPrefix("0x") {
            hexString = String(hexString.dropFirst(2))
        }
        return UInt64(hexString, radix: 16) ?? 0
    }
}

// MARK: - Transaction History Service

final class TransactionHistoryService {
    static let shared = TransactionHistoryService()
    
    private let historyKey = "com.cryptowallet.txhistory"
    
    enum TransactionStatus: String, Codable {
        case pending
        case confirmed
        case failed
    }
    
    struct TransactionRecord: Codable {
        let hash: String
        let from: String
        let to: String
        let value: String
        let timestamp: Date
        var status: TransactionStatus
    }
    
    private init() {}
    
    func addTransaction(hash: String, from: String, to: String, value: String, status: TransactionStatus) {
        var history = getHistory()
        let record = TransactionRecord(
            hash: hash,
            from: from,
            to: to,
            value: value,
            timestamp: Date(),
            status: status
        )
        history.insert(record, at: 0)
        saveHistory(history)
    }
    
    func updateTransactionStatus(hash: String, status: TransactionStatus) {
        var history = getHistory()
        if let index = history.firstIndex(where: { $0.hash == hash }) {
            var record = history[index]
            record.status = status
            history[index] = record
            saveHistory(history)
        }
    }
    
    func getHistory(forAddress address: String? = nil) -> [TransactionRecord] {
        guard let data = UserDefaults.standard.data(forKey: historyKey),
              let history = try? JSONDecoder().decode([TransactionRecord].self, from: data) else {
            return []
        }
        
        if let address = address {
            return history.filter { $0.from == address || $0.to == address }
        }
        return history
    }
    
    private func saveHistory(_ history: [TransactionRecord]) {
        if let data = try? JSONEncoder().encode(history) {
            UserDefaults.standard.set(data, forKey: historyKey)
        }
    }
}

// MARK: - Wallet Manager (Main Interface)

final class WalletManager: ObservableObject {
    static let shared = WalletManager()
    
    @Published var wallets: [Wallet] = []
    @Published var selectedWallet: Wallet?
    @Published var balance: BlockchainBalance?
    @Published var isLoading: Bool = false
    @Published var errorMessage: String?
    @Published var transactionHistory: [TransactionHistoryService.TransactionRecord] = []
    
    private init() {
        loadWallets()
    }
    
    func loadWallets() {
        wallets = WalletStorageService.shared.loadWallets()
        if selectedWallet == nil {
            selectedWallet = wallets.first
        }
    }
    
    func createNewWallet() throws -> KeyGenerationService.GeneratedWallet {
        let generated = try KeyGenerationService.shared.generateWallet()
        loadWallets()
        selectedWallet = generated.wallet
        return generated
    }
    
    func importWallet(privateKeyHex: String) throws -> Wallet {
        let wallet = try KeyGenerationService.shared.importWallet(privateKeyHex: privateKeyHex)
        loadWallets()
        selectedWallet = wallet
        return wallet
    }
    
    func deleteWallet(_ wallet: Wallet) throws {
        try KeyGenerationService.shared.deleteWallet(address: wallet.address)
        loadWallets()
        if selectedWallet?.address == wallet.address {
            selectedWallet = wallets.first
        }
    }
    
    func refreshBalance() async {
        guard let wallet = selectedWallet else { return }
        
        await MainActor.run { isLoading = true }
        
        do {
            let bal = try await BlockchainService.shared.getBalance(address: wallet.address)
            await MainActor.run {
                self.balance = bal
                self.isLoading = false
            }
        } catch {
            await MainActor.run {
                self.errorMessage = error.localizedDescription
                self.isLoading = false
            }
        }
    }
    
    func sendTransaction(to: String, valueInEth: Double) async throws -> String {
        guard let wallet = selectedWallet else {
            throw WalletError.invalidAddress
        }
        
        let valueInWei = String(format: "0x%llx", UInt64(valueInEth * 1e18))
        
        let txHash = try await BlockchainService.shared.buildAndSendTransaction(
            from: wallet.address,
            to: to,
            valueInWei: valueInWei
        )
        
        await refreshBalance()
        loadTransactionHistory()
        
        return txHash
    }
    
    func signMessage(_ message: String) throws -> String {
        guard let wallet = selectedWallet else {
            throw WalletError.invalidAddress
        }
        
        return try TransactionSigningService.shared.signPersonalMessage(
            message,
            withAddress: wallet.address
        )
    }
    
    func loadTransactionHistory() {
        guard let wallet = selectedWallet else { return }
        transactionHistory = TransactionHistoryService.shared.getHistory(forAddress: wallet.address)
    }
}

