struct TransactionRowView: View {
    let transaction: TransactionHistoryService.TransactionRecord
    let currentAddress: String
    
    var body: some View {
        HStack {
            Image(systemName: transaction.from.lowercased() == currentAddress.lowercased() ? "arrow.up.right" : "arrow.down.left")
                .foregroundColor(transaction.from.lowercased() == currentAddress.lowercased() ? .red : .green)
                .frame(width: 30)
            
            VStack(alignment: .leading, spacing: 4) {
                Text(shortenHash(transaction.hash))
                    .font(.subheadline)
                    .fontWeight(.medium)
                
                Text(transaction.timestamp, style: .relative)
                    .font(.caption)
                    .foregroundColor(.secondary)
            }
            
            Spacer()
            
            VStack(alignment: .trailing, spacing: 4) {
                Text(transaction.value)
                    .font(.caption)
                    .lineLimit(1)
                
                statusBadge
            }
        }
        .padding(.vertical, 8)
    }
    
    private var statusBadge: some View {
        Text(transaction.status.rawValue.capitalized)
            .font(.caption2)
            .padding(.horizontal, 8)
            .padding(.vertical, 2)
            .background(statusColor.opacity(0.2))
            .foregroundColor(statusColor)
            .cornerRadius(4)
    }
    
    private var statusColor: Color {
        switch transaction.status {
        case .pending: return .orange
        case .confirmed: return .green
        case .failed: return .red
        }
    }
    
    private func shortenHash(_ hash: String) -> String {
        guard hash.count > 14 else { return hash }
        return "\(hash.prefix(8))...\(hash.suffix(6))"
    }
}

