            VStack(spacing: 20) {
                if let hash = txHash {
                    transactionSentView(hash: hash)
                } else {
                    sendFormView
                }
            }
            .padding()
            .navigationTitle("Send ETH")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .navigationBarLeading) {
                    Button("Cancel") { dismiss() }
                }
            }
        }
    }
    
    private var sendFormView: some View {
        VStack(alignment: .leading, spacing: 16) {
            VStack(alignment: .leading, spacing: 8) {
                Text("From")
                    .font(.caption)
                    .foregroundColor(.secondary)
                
                Text(walletManager.selectedWallet?.address ?? "No wallet selected")
                    .font(.system(.caption, design: .monospaced))
                    .padding(12)
                    .background(Color(.systemGray6))
                    .cornerRadius(8)
            }
            
            VStack(alignment: .leading, spacing: 8) {
                Text("To")
                    .font(.caption)
                    .foregroundColor(.secondary)
                
                TextField("Recipient address (0x...)", text: $recipientAddress)
                    .textFieldStyle(.roundedBorder)
                    .font(.system(.body, design: .monospaced))
                    .autocapitalization(.none)
                    .disableAutocorrection(true)
            }
            
            VStack(alignment: .leading, spacing: 8) {
                Text("Amount (ETH)")
                    .font(.caption)
                    .foregroundColor(.secondary)
                
                TextField("0.0", text: $amount)
                    .textFieldStyle(.roundedBorder)
                    .keyboardType(.decimalPad)
            }
            
            if let balance = walletManager.balance {
                Text("Available: \(String(format: "%.6f", balance.balanceEth)) ETH")
                    .font(.caption)
                    .foregroundColor(.secondary)
            }
            
            if let error = error {
                Text(error)
                    .font(.caption)
                    .foregroundColor(.red)
                    .padding()
                    .background(Color.red.opacity(0.1))
                    .cornerRadius(8)
            }
            
            Spacer()
            
            Button(action: sendTransaction) {
                if isProcessing {
                    ProgressView()
                        .progressViewStyle(CircularProgressViewStyle(tint: .white))
                        .frame(maxWidth: .infinity)
                        .padding()
                        .background(Color.gray)
                        .cornerRadius(12)
                } else {
                    Text("Send Transaction")
                        .fontWeight(.semibold)
                        .frame(maxWidth: .infinity)
                        .padding()
                        .background(isFormValid ? Color.blue : Color.gray)
                        .foregroundColor(.white)
                        .cornerRadius(12)
                }
            }
            .disabled(!isFormValid || isProcessing)
        }
    }
    
